export function tagPost(body: string): string {
  return body.toUpperCase();
}

export function slugify(input: string): string {
  return input.toLowerCase().replace(/\s+/g, "-");
}

export function formatLabel(label: string): string {
  return `[${label}]`;
}

export function buildSlug(title: string): string {
  return title.toLowerCase().trim().replace(/\s+/g, "-");
}

export function auditSku(sku: string): string {
  return `AUDIT:${sku}`;
}

export function describeItem(name: string): string {
  return `item:${name}`;
}

export function escalationLabel(reason: string): string {
  return `ESCALATED:${reason}`;
}

export function archiveTag(reference: string): string {
  return `archived/${reference}`;
}

export function formatCode(x: string): string {
  return x.toUpperCase();
}

export function makeTagline(x: string): string {
  return x + "!";
}
